import{_ as o,o as t,c as a,ag as n}from"./chunks/framework.D4O_uTxf.js";const h=JSON.parse('{"title":"Venture Track C Control Plane","description":"","frontmatter":{},"headers":[],"relativePath":"venture/track-c.md","filePath":"venture/track-c.md","lastUpdated":1771844172000}'),i={name:"venture/track-c.md"};function c(r,e,s,l,d,u){return t(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="venture-track-c-control-plane" tabindex="-1">Venture Track C Control Plane <a class="header-anchor" href="#venture-track-c-control-plane" aria-label="Permalink to &quot;Venture Track C Control Plane&quot;">​</a></h1><p>Source mirror: <code>./venture/TRACK_C_CONTROL_PLANE.md</code></p><h1 id="venture-track-c-control-plane-closure" tabindex="-1">Venture Track C Control-Plane Closure <a class="header-anchor" href="#venture-track-c-control-plane-closure" aria-label="Permalink to &quot;Venture Track C Control-Plane Closure&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Track C binds the Venture autonomy control plane into a closed system: authenticated identities, explicit isolation boundaries, policy-based tool access, tamper-evident events, and governed rollout/incident behavior. The deliverable below stitches the Venture specification sources with the civ/infra agent-workspace scaffolds so every decision is grounded in an auditable schema.</p><h2 id="identity-scoped-isolation-and-tool-allowlists" tabindex="-1">Identity, Scoped Isolation, and Tool Allowlists <a class="header-anchor" href="#identity-scoped-isolation-and-tool-allowlists" aria-label="Permalink to &quot;Identity, Scoped Isolation, and Tool Allowlists&quot;">​</a></h2><ul><li><strong>Workload identity</strong>: follow the Technical Spec’s requirement for short-lived credentials and mTLS (&quot;Workload identity and short-lived credentials&quot; plus &quot;Workload identity, mTLS, and credential rotation&quot;). Every agent session must assert a pinned <code>agent_role</code> or <code>workspace_id</code> inside the Task Envelope schema (<code>task_id</code>, <code>workflow_id</code>, <code>agent_role</code>, <code>input</code>, <code>created_at</code>).</li><li><strong>Isolation boundary</strong>: enclave each agent in the role-specific workspace defined in <code>workspaces/default.yaml</code> (e.g., <code>civ-default</code>) with <code>max_concurrency</code> guardrails, <code>retry_policy</code>, and capped budgets (<code>global_eau_cap</code>, <code>per_workflow_eau_cap</code>). This ensures every run is time-boxed, budget-limited, and traceable before it touches external tools.</li><li><strong>Tool allowlists</strong>: enforce the civ/infra policy at <code>policy/tool-allowlists.yaml</code>. Each named role (or an overtime-managed alias) can only use the declared tools (<code>workflow.dispatch</code>, <code>policy.evaluate</code>, <code>event.publish</code>, <code>io.read</code>, <code>web.fetch</code>, <code>artifact.render</code>, etc.). Align any additional permissible tool with a change request that updates this YAML, accompanied by a new policy version in the Product/Operations specs.</li><li><strong>Composition</strong>: Combine schema validation with policy enforcement before handing tasks to agents: validate <code>task_type</code> against schemas, inject <code>trace_id</code> and <code>workflow_id</code>, shape <code>input</code> via the Task Envelope, then check the requested tool set against the role’s allowlist.</li></ul><h2 id="event-bus-fsm-pack" tabindex="-1">Event Bus + FSM Pack <a class="header-anchor" href="#event-bus-fsm-pack" aria-label="Permalink to &quot;Event Bus + FSM Pack&quot;">​</a></h2><ul><li><strong>Event toxicity</strong>: Use the Venture API Events list as your topic catalog (<code>policy.published.v1</code>, <code>workflow.started.v1</code>, etc.) and honor the Event Envelope schema (<code>event_id</code>, <code>event_type</code>, <code>trace_id</code>, <code>workflow_id</code>, <code>task_id</code>, <code>payload</code>, <code>created_at</code>). Emit every state transition from finite state machines (FSMs) as one of these events so the audit chain is uniform.</li><li><strong>FSM pack</strong>: model orchestration steps (workflow → task → agent action → artifact generation) as FSM states that fire events on entry/exit. Keep <code>trace_id</code> and <code>workflow_id</code> identical across <code>task.completed.v1</code>, <code>artifact.generated.v1</code>, <code>money.intent.created.v1</code>, etc., by stuffing them into the event payload per the schema and reusing them for retrieve/replay.</li><li><strong>Schema binding</strong>: before publishing events, assert the payload shape with the same policy-driven schema registry that the control plane uses (per Technical Spec’s &quot;Schema registry and event bus&quot;). Use <code>policy_bundle</code> versions (DB spec) to tie every emitted event to a known policy version for provenance.</li><li><strong>Event consumer contracts</strong>: document each listener&#39;s expected <code>payload</code> subset and any FSM guard transitions (e.g., the treasury FSM waits for <code>money.authorization.decided.v1</code> before dispatching <code>ledger.entry.created.v1</code>). Keep this doc synchronized with the API events spec to avoid silent drift.</li></ul><h2 id="observability-and-audit" tabindex="-1">Observability and Audit <a class="header-anchor" href="#observability-and-audit" aria-label="Permalink to &quot;Observability and Audit&quot;">​</a></h2><ul><li><strong>Mandatory context</strong>: enforce <code>require_trace_id</code> and <code>require_event_envelope</code> as dictated by <code>workspaces/default.yaml</code> so no action is recorded without a unique <code>trace_id</code> and the <code>EventEnvelopeV1</code> context.</li><li><strong>Tamper-evident logs</strong>: mirror the Ops Compliance Spec’s requirement for tamper-evident logs and periodic integrity attestations. Pipe all events and DB writes through an append-only log (+ checksum) that records <code>created_at</code> (ISO 8601) and policy bundle version.</li><li><strong>Audit cadence</strong>: schedule daily reconciliation checks, weekly policy-drift reviews, monthly governance attestations, and quarterly tabletop incident drills (Ops Compliance Spec’s Audits section). Capture proof artifacts (log snapshot, policy version, event ID ranges) in a retrievable bucket for each cadence.</li><li><strong>Observability layers</strong>: instrument the FSM pack to emit metrics/alerts for state duration, tool invocation counts, policy evaluation latency, event publish success, and budget consumption (per workspace budget caps). Integrate with the Ops spec’s fiscal oversight surfaces (Treasury/Compliance dashboards) so the gaps are visible to Finance Controllers and Operations Auditors.</li></ul><h2 id="rollout-stages" tabindex="-1">Rollout Stages <a class="header-anchor" href="#rollout-stages" aria-label="Permalink to &quot;Rollout Stages&quot;">​</a></h2><ol><li><strong>Sandbox verification</strong> (pre-policy lock): run new policies and FSM transitions in a staging workspace, ensure <code>tool-allowlists</code> and event payloads validate against the schemas, and confirm budgets/trace IDs persist.</li><li><strong>Gate</strong> (policy publish + policy bundle pinning): once compliance/finance owners sign-off, publish the policy via <code>POST /policies/publish</code> (API spec) and pin the bundle ID on the workflow. This stage still only uses orchestrator/researcher/solver roles under a manual approval gate.</li><li><strong>Controlled ramp</strong> (limited workspace concurrency, monitoring, alerting): allow a subset of workflows (e.g., low-risk <code>task_type</code>s) to execute with the full FSM pack, event bus, audit logging, and budget enforcement. Observe incident metrics and escalate if thresholds exceed.</li><li><strong>Full launch</strong> (policy fully enforced, budgets tuned): remove manual gates, allow necessary roles, and run the entire product model surface stack (control-plane editor, treasury firewall, compliance cockpit). Keep a shadow copy of budgets and audit proofs for retroactive compliance.</li></ol><ul><li>Each stage should be recorded as an FSM transition and event; stage gates trigger <code>workflow.started.v1</code> or bespoke <code>rollout.stage.changed.v1</code> events.</li></ul><h2 id="incident-doctrine" tabindex="-1">Incident Doctrine <a class="header-anchor" href="#incident-doctrine" aria-label="Permalink to &quot;Incident Doctrine&quot;">​</a></h2><ul><li><strong>Incident classes &amp; escalation</strong>: follow Ops controls—classify incidents into predefined buckets (example: policy violation, treasury drift, tool misuse, compliance/legal). Map each class to an escalation path (on-call, compliance SME, founder governor) and include predefined playbooks.</li><li><strong>Freeze/kill switch</strong>: align with Ops controls (&quot;Freeze mode and global kill-switch behavior&quot;). Upon a Class 1 breach (budget overrun, root policy violation), immediately pause orchestrator execution (retaining event logs), flip the kill switch, and inform the compliance channel.</li><li><strong>Evidence capture</strong>: when incidents fire, record at least one <code>event_id</code> per impacted FSM transition, the implicated <code>policy_bundle</code> version, and the workspace/budget context. These become the starting point for the audit drill schedule described above.</li><li><strong>Postmortem</strong>: require compliance/audit review and a policy bundle re-evaluation before reactivating any halted FSM flows. Document lessons learned via the <code>policy.evaluate</code> workflow, tie them to updated <code>policy_bundle</code> IDs, and disseminate to Controllers/Auditors.</li></ul><h2 id="references-next-steps" tabindex="-1">References &amp; Next Steps <a class="header-anchor" href="#references-next-steps" aria-label="Permalink to &quot;References &amp; Next Steps&quot;">​</a></h2><ul><li>Venture specs: <code>TECHNICAL_SPEC.md</code>, <code>API_EVENTS_SPEC.md</code>, <code>DATA_MODEL_DB_SPEC.md</code>, <code>OPS_COMPLIANCE_SPEC.md</code>, <code>PRODUCT_MODEL.md</code>, <code>USER_SPEC.md</code>.</li><li>Scaffolds: <code>../civ/infra/agent-workspace/policy/tool-allowlists.yaml</code>, <code>../civ/infra/agent-workspace/schemas/task-envelope.v1.json</code>, <code>../civ/infra/agent-workspace/schemas/event-envelope.v1.json</code>, <code>../civ/infra/agent-workspace/workspaces/default.yaml</code>.</li><li>Next: validate FSM transitions against tool allowlist updates, codify stage-gate event metrics, and bake incident playbooks into the policy bundle review flow.</li></ul>',18)])])}const v=o(i,[["render",c]]);export{h as __pageData,v as default};
